import re

def validate_hkid(hkid: str) -> bool:
    cleaned = hkid.strip().upper().replace(' ', '')
    match = re.match(r'^([A-Z]{1,2})(\d{6})\(?([0-9A])\)?$', cleaned)
    if not match:
        return False
    prefix, digits_str, check_char = match.groups()
    if len(prefix) == 1:
        values = [36, ord(prefix) - 55]
    else:
        values = [ord(prefix[0]) - 55, ord(prefix[1]) - 55]
    values.extend(int(d) for d in digits_str)
    weights = [9, 8, 7, 6, 5, 4, 3, 2]
    total = sum(v * w for v, w in zip(values, weights))
    remainder = total % 11
    if remainder == 0:
        expected = '0'
    elif remainder == 1:
        expected = 'A'
    else:
        expected = str(11 - remainder)
    return check_char == expected

import re

def format_hk_phone(phone: str) -> str:
    digits = re.sub(r'\D', '', phone)
    if digits.startswith('852') and len(digits) == 11:
        digits = digits[3:]
    if len(digits) != 8:
        raise ValueError(f'HK phone numbers must be 8 digits, got {len(digits)}')
    return f'+852 {digits[:4]} {digits[4:]}'

def is_mobile(phone: str) -> bool:
    digits = re.sub(r'\D', '', phone)
    if digits.startswith('852') and len(digits) == 11:
        digits = digits[3:]
    return len(digits) == 8 and digits[0] in '5679'

from dataclasses import dataclass
from typing import Literal

@dataclass
class BilingualText:
    en: str
    zh: str

    def get(self, lang: Literal['en', 'zh'] = 'en') -> str:
        return self.zh if lang == 'zh' else self.en

    def __str__(self) -> str:
        return f'{self.en} / {self.zh}'

    def to_dict(self) -> dict:
        return {'en': self.en, 'zh': self.zh}

    @classmethod
    def from_dict(cls, data: dict) -> 'BilingualText':
        return cls(en=data.get('en', ''), zh=data.get('zh', ''))

# Usage:
name = BilingualText(en='Central', zh='中環')
print(name.get('zh'))  # 中環

from datetime import date, datetime

DAY_NAMES_ZH = ['星期一', '星期二', '星期三', '星期四', '星期五', '星期六', '星期日']
MONTH_NAMES_ZH = ['一月', '二月', '三月', '四月', '五月', '六月', '七月', '八月', '九月', '十月', '十一月', '十二月']

def format_hk_date(d: date, lang: str = 'en') -> str:
    if lang == 'zh':
        return f'{d.year}年{d.month}月{d.day}日 ({DAY_NAMES_ZH[d.weekday()]})'
    return d.strftime('%d/%m/%Y (%A)')

def format_hk_datetime(dt: datetime, lang: str = 'en') -> str:
    if lang == 'zh':
        period = '上午' if dt.hour < 12 else '下午'
        hour = dt.hour if dt.hour <= 12 else dt.hour - 12
        return f'{dt.year}年{dt.month}月{dt.day}日 {period}{hour}:{dt.minute:02d}'
    return dt.strftime('%d/%m/%Y %I:%M %p')

# Usage:
today = date.today()
print(format_hk_date(today, 'en'))  # 06/03/2026 (Friday)
print(format_hk_date(today, 'zh'))  # 2026年3月6日 (星期五)

from dataclasses import dataclass, field

@dataclass
class MTRStation:
    code: str
    name_en: str
    name_zh: str
    lines: list[str] = field(default_factory=list)

MTR_STATIONS = {
    'CEN': MTRStation('CEN', 'Central', '中環', ['ISL', 'TWL']),
    'ADM': MTRStation('ADM', 'Admiralty', '金鐘', ['ISL', 'TWL', 'SIL', 'EAL']),
    'TST': MTRStation('TST', 'Tsim Sha Tsui', '尖沙咀', ['TWL']),
    'MKK': MTRStation('MKK', 'Mong Kok', '旺角', ['KTL']),
    'KOT': MTRStation('KOT', 'Kowloon Tong', '九龍塘', ['KTL', 'EAL']),
    'TKO': MTRStation('TKO', 'Tseung Kwan O', '將軍澳', ['TKL']),
    'SHT': MTRStation('SHT', 'Sha Tin', '沙田', ['EAL']),
}

def find_station(query: str) -> list[MTRStation]:
    q = query.lower()
    return [
        s for s in MTR_STATIONS.values()
        if q in s.name_en.lower() or q in s.name_zh or q == s.code.lower()
    ]

from decimal import Decimal, ROUND_HALF_UP

def format_hkd(amount: float | Decimal, lang: str = 'en') -> str:
    d = Decimal(str(amount)).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
    formatted = f'{d:,.2f}'
    if lang == 'zh':
        return f'港幣 {formatted} 元'
    return f'HK${formatted}'

def parse_hkd(text: str) -> Decimal:
    cleaned = text.replace('HK$', '').replace('港幣', '').replace('元', '').replace(',', '').strip()
    return Decimal(cleaned)

# Usage:
print(format_hkd(12345.60))         # HK$12,345.60
print(format_hkd(12345.60, 'zh'))   # 港幣 12,345.60 元
